import { getSiteUrl } from '@/lib/site-config'

const EVOLUTION_URL = process.env.EVOLUTION_API_URL
const EVOLUTION_API_KEY: string = process.env.EVOLUTION_API_KEY || ''
const EVOLUTION_INSTANCE: string = process.env.EVOLUTION_INSTANCE || ''
const ADMIN_NUMBER = process.env.ADMIN_WHATSAPP

function requireWhatsAppConfig() {
  if (!EVOLUTION_API_KEY) throw new Error('[WhatsApp] EVOLUTION_API_KEY not configured')
  if (!EVOLUTION_INSTANCE) throw new Error('[WhatsApp] EVOLUTION_INSTANCE not configured')
}

function cleanNumber(number: string): string {
  return number.replace(/[^0-9]/g, '')
}

export async function sendWhatsApp(to: string, message: string): Promise<boolean> {
  requireWhatsAppConfig()
  const number = cleanNumber(to)
  try {
    const res = await fetch(
      `${EVOLUTION_URL}/message/sendText/${EVOLUTION_INSTANCE}`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'apikey': EVOLUTION_API_KEY,
        } as Record<string, string>,
        body: JSON.stringify({
          number,", "exit_code": 0, "error": null}
